const fs = require\('fs'\);
const data = JSON.parse\(fs.readFileSync\('C:/Users/justi/OneDrive/Documents/Code_Repository/Workspace/j-guyy.github.io/data/skiResorts.json'\)\);
const visited = new Set\(data.filter\(r => r.visited\).map\(r => r.name\)\);
const userList = [
  'West Mountain','Willard Mountain','Jiminy Peak','Gore Mountain','Whiteface Mountain',
  'Killington','Windham Mountain','Blue Mountain \(PA\)','Park City','Vail',
  'Stevens Pass','Whistler Blackcomb','Hoodoo','Copper Mountain','Killington',
  'Steamboat','Deer Valley','Snowbird','Solitude Mountain','Alta','Winter Park',
  'Aspen Mountain','Revelstoke','Jackson Hole','Arapahoe Basin','Mammoth Mountain',
  'Sugarbush','Big Sky','Eldora','Chamonix Mont-Blanc','Crystal Mountain','Zermatt'
];
const userSet = new Set\(userList\);
console.log\('In JSON visited but NOT in your list:'\);
[...visited].filter\(r => !userSet.has\(r\)\).forEach\(r => console.log\(' -', r\)\);
console.log\(''\);
console.log\('In your list but NOT marked visited in JSON:'\);
userList.filter\(r => !visited.has\(r\)\).forEach\(r => console.log\(' -', r\)\);
")

